use serde::{Deserialize, Serialize};

use crate::serialization::{PolyglotFunctionResult, PolyglotOrchestrationResult};
use crate::substrate_bridge::{fano_cache_key, protocol69_is_fano, triton_collide};

pub const PROTOCOL69_APP_SCHEMA_VERSION: &str = "gnosis.protocol69.polyglot-app-teleport.v1";
pub const PROTOCOL69_APP_RECEIPT_SCHEMA_VERSION: &str =
    "gnosis.protocol69.polyglot-app-cache-receipt.v1";
pub const PROTOCOL69_APP_CACHE_KEY_PREFIX: &str = "gnosis:protocol69:polyglot-app-cache:v1";
pub const PROTOCOL69_APP_TELEPORT_KIND: &str = "polyglot-app->gg->protocol69-cache-key";
pub const PROTOCOL69_RECEIPT_RETURN: &str = "compute-cache-key";
pub const PROTOCOL69_LEAN_MODULE: &str = "Gnosis.Protocol69IotaTeleport";
pub const PROTOCOL69_BROADCAST_OPERAND: u8 = 66;
pub const PROTOCOL69_LOCAL_FOIL_OPERAND: u8 = 7;
pub const PROTOCOL69_PROJECTED_PROTOCOL: u8 = 69;

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69InRoomRfSession {
    pub transport: String,
    pub radio: String,
    pub antenna_count: usize,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub room_id: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub carrier_hz: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub attenuation_db: Option<i64>,
}

impl Default for Protocol69InRoomRfSession {
    fn default() -> Self {
        Self {
            transport: "in-room-rf".to_string(),
            radio: "pluto-sdr".to_string(),
            antenna_count: 2,
            room_id: None,
            carrier_hz: None,
            attenuation_db: None,
        }
    }
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69PolyglotAppKeyMaterial {
    pub lean_module: String,
    pub language: String,
    pub file_path: String,
    pub function_name: String,
    pub gg_node_count: usize,
    pub gg_edge_count: usize,
    pub execution_node_count: usize,
    pub projection_operand: u8,
    pub local_operand: u8,
    pub projected_protocol: u8,
    pub triton_fano_point: u8,
    pub program_fano_cache_slot: u8,
    pub program_checksum: String,
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69PolyglotAppCacheReceipt {
    pub schema_version: String,
    pub teleport_kind: String,
    pub receipt_return: String,
    pub session: Protocol69InRoomRfSession,
    pub key_material: Protocol69PolyglotAppKeyMaterial,
    pub compute_cache_key: String,
    pub gg_source: String,
}

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct Protocol69PolyglotAppTeleportReport {
    pub schema_version: String,
    pub teleport_kind: String,
    pub receipt_return: String,
    pub session: Protocol69InRoomRfSession,
    pub file_path: String,
    pub language: String,
    pub receipts: Vec<Protocol69PolyglotAppCacheReceipt>,
    pub errors: Vec<String>,
}

pub fn protocol69_default_in_room_rf_session() -> Protocol69InRoomRfSession {
    Protocol69InRoomRfSession::default()
}

pub fn protocol69_stable_checksum(input: &str) -> String {
    let mut hash = 0x811c_9dc5u32;
    for unit in input.encode_utf16() {
        hash ^= u32::from(unit);
        hash = hash.wrapping_mul(0x0100_0193);
    }
    format!("{hash:08x}")
}

pub fn build_protocol69_polyglot_app_teleport_report(
    orchestration: &PolyglotOrchestrationResult,
    session: Protocol69InRoomRfSession,
) -> Protocol69PolyglotAppTeleportReport {
    let receipts = orchestration
        .scan_result
        .topologies
        .iter()
        .map(|function| {
            build_protocol69_polyglot_app_cache_receipt(
                function,
                &orchestration.scan_result.language,
                &orchestration.scan_result.file_path,
                session.clone(),
            )
        })
        .collect();

    Protocol69PolyglotAppTeleportReport {
        schema_version: PROTOCOL69_APP_SCHEMA_VERSION.to_string(),
        teleport_kind: PROTOCOL69_APP_TELEPORT_KIND.to_string(),
        receipt_return: PROTOCOL69_RECEIPT_RETURN.to_string(),
        session,
        file_path: orchestration.scan_result.file_path.clone(),
        language: orchestration.scan_result.language.clone(),
        receipts,
        errors: orchestration
            .scan_result
            .errors
            .iter()
            .map(|error| error.message.clone())
            .collect(),
    }
}

pub fn build_protocol69_polyglot_app_cache_receipt(
    function: &PolyglotFunctionResult,
    language: &str,
    file_path: &str,
    session: Protocol69InRoomRfSession,
) -> Protocol69PolyglotAppCacheReceipt {
    let program_checksum = protocol69_stable_checksum(&function.gg_source);
    let key_material =
        build_protocol69_polyglot_app_key_material(function, language, file_path, program_checksum);
    let compute_cache_key =
        protocol69_polyglot_app_compute_cache_key(&function.gg_source, &session, &key_material);

    Protocol69PolyglotAppCacheReceipt {
        schema_version: PROTOCOL69_APP_RECEIPT_SCHEMA_VERSION.to_string(),
        teleport_kind: PROTOCOL69_APP_TELEPORT_KIND.to_string(),
        receipt_return: PROTOCOL69_RECEIPT_RETURN.to_string(),
        session,
        key_material,
        compute_cache_key,
        gg_source: function.gg_source.clone(),
    }
}

pub fn protocol69_polyglot_app_compute_cache_key(
    gg_source: &str,
    session: &Protocol69InRoomRfSession,
    key_material: &Protocol69PolyglotAppKeyMaterial,
) -> String {
    let material = format!(
        "{}|{}|{}",
        gg_source,
        key_material_stable_material(key_material),
        session_stable_material(session)
    );
    format!(
        "{PROTOCOL69_APP_CACHE_KEY_PREFIX}:{}",
        protocol69_stable_checksum(&material)
    )
}

fn build_protocol69_polyglot_app_key_material(
    function: &PolyglotFunctionResult,
    language: &str,
    file_path: &str,
    program_checksum: String,
) -> Protocol69PolyglotAppKeyMaterial {
    let triton_fano_point = triton_collide(
        PROTOCOL69_BROADCAST_OPERAND % 8,
        PROTOCOL69_LOCAL_FOIL_OPERAND % 8,
    );
    let projected_protocol = PROTOCOL69_BROADCAST_OPERAND ^ PROTOCOL69_LOCAL_FOIL_OPERAND;
    debug_assert_eq!(projected_protocol, PROTOCOL69_PROJECTED_PROTOCOL);
    debug_assert!(protocol69_is_fano(
        PROTOCOL69_BROADCAST_OPERAND,
        PROTOCOL69_LOCAL_FOIL_OPERAND
    ));

    Protocol69PolyglotAppKeyMaterial {
        lean_module: PROTOCOL69_LEAN_MODULE.to_string(),
        language: language.to_string(),
        file_path: file_path.to_string(),
        function_name: function.function_name.clone(),
        gg_node_count: function.topology.nodes.len(),
        gg_edge_count: function.topology.edges.len(),
        execution_node_count: execution_node_count(function),
        projection_operand: PROTOCOL69_BROADCAST_OPERAND,
        local_operand: PROTOCOL69_LOCAL_FOIL_OPERAND,
        projected_protocol,
        triton_fano_point,
        program_fano_cache_slot: checksum_fano_slot(&program_checksum),
        program_checksum,
    }
}

fn execution_node_count(function: &PolyglotFunctionResult) -> usize {
    function
        .topology
        .nodes
        .iter()
        .filter(|node| {
            node.labels
                .iter()
                .any(|label| label.starts_with("PolyglotBridge"))
        })
        .count()
}

fn checksum_fano_slot(checksum: &str) -> u8 {
    let value = u64::from_str_radix(checksum, 16).unwrap_or(0);
    fano_cache_key(value)
}

fn key_material_stable_material(key_material: &Protocol69PolyglotAppKeyMaterial) -> String {
    format!(
        "{}|{}|{}|{}|{}|{}|{}|{}|{}|{}|{}|{}|{}",
        key_material.lean_module,
        key_material.language,
        key_material.file_path,
        key_material.function_name,
        key_material.gg_node_count,
        key_material.gg_edge_count,
        key_material.execution_node_count,
        key_material.projection_operand,
        key_material.local_operand,
        key_material.projected_protocol,
        key_material.triton_fano_point,
        key_material.program_fano_cache_slot,
        key_material.program_checksum,
    )
}

fn session_stable_material(session: &Protocol69InRoomRfSession) -> String {
    format!(
        "{}|{}|{}|{}|{}|{}",
        session.transport,
        session.radio,
        session.antenna_count,
        session.room_id.as_deref().unwrap_or(""),
        session
            .carrier_hz
            .map(|value| value.to_string())
            .unwrap_or_default(),
        session
            .attenuation_db
            .map(|value| value.to_string())
            .unwrap_or_default(),
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn stable_checksum_is_deterministic() {
        assert_eq!(
            protocol69_stable_checksum("abc"),
            protocol69_stable_checksum("abc")
        );
        assert_ne!(
            protocol69_stable_checksum("abc"),
            protocol69_stable_checksum("abd")
        );
    }

    #[test]
    fn builds_cache_receipt_for_supported_application_source() {
        let source = r#"
export async function app(input: { n: number }) {
  const next = input.n + 1;
  return next;
}
"#;
        let orchestration =
            crate::parse_and_extract_orchestration(source, "in_room_app.ts").unwrap();
        let report = build_protocol69_polyglot_app_teleport_report(
            &orchestration,
            Protocol69InRoomRfSession {
                room_id: Some("lab-a".to_string()),
                carrier_hz: Some(2_400_000_000),
                attenuation_db: Some(30),
                ..Protocol69InRoomRfSession::default()
            },
        );

        assert!(report.errors.is_empty());
        assert_eq!(report.schema_version, PROTOCOL69_APP_SCHEMA_VERSION);
        assert_eq!(report.receipt_return, PROTOCOL69_RECEIPT_RETURN);
        assert!(!report.receipts.is_empty());

        let receipt = &report.receipts[0];
        assert!(receipt
            .compute_cache_key
            .starts_with(PROTOCOL69_APP_CACHE_KEY_PREFIX));
        assert_eq!(receipt.key_material.projection_operand, 66);
        assert_eq!(receipt.key_material.local_operand, 7);
        assert_eq!(receipt.key_material.projected_protocol, 69);
        assert_eq!(receipt.key_material.triton_fano_point, 5);
        assert_eq!(
            receipt.key_material.gg_node_count,
            orchestration.scan_result.topologies[0].topology.nodes.len()
        );
        assert_eq!(
            receipt.key_material.gg_edge_count,
            orchestration.scan_result.topologies[0].topology.edges.len()
        );
    }

    #[test]
    fn cache_key_changes_when_rf_session_changes() {
        let source = r#"
function main() {
  return 69;
}
"#;
        let orchestration =
            crate::parse_and_extract_orchestration(source, "session_sensitive.js").unwrap();
        let function = &orchestration.scan_result.topologies[0];
        let first = build_protocol69_polyglot_app_cache_receipt(
            function,
            "javascript",
            "session_sensitive.js",
            Protocol69InRoomRfSession::default(),
        );
        let second = build_protocol69_polyglot_app_cache_receipt(
            function,
            "javascript",
            "session_sensitive.js",
            Protocol69InRoomRfSession {
                room_id: Some("other-room".to_string()),
                ..Protocol69InRoomRfSession::default()
            },
        );

        assert_ne!(first.compute_cache_key, second.compute_cache_key);
    }
}
